function secureDocumentContent() {
  // दस्तावेज़ के उपकरण में मौजूद सामग्री को पढ़ना
  const content = fs.readFileSync(path.join(DOCUMENT_TOOL_PATH, 'content.txt'), 'utf8');

  // सामग्री को एन्क्रिप्ट करने के लिए एक प्रमुख कुंजी का उपयोग करें
  const encryptionKey ='my_secret_key';
  const encryptedContent = encrypt(content, encryptionKey);

  // एन्क्रिप्ट की गई सामग्री को एक फ़ाइल में लिखना
  fs.writeFileSync(path.join(DOCUMENT_TOOL_PATH, 'encrypted_content.txt'), encryptedContent);
}

// सामग्री को एन्क्रिप्ट करने के लिए एक फ़ंक्शन
function encrypt(content, key) {
  // एक एन्क्रिप्शन एल्गोरिदम का उपयोग करें (उदाहरण के लिए, AES)
  const crypto = require('crypto');
  const cipher = crypto.createCipheriv('aes-256-cbc', key, Buffer.alloc(16));
  let encrypted = cipher.update(content, 'utf8', 'hex');
  encrypted += cipher.final('hex');
  return encrypted;
}

